<?php
require_once dirname(__DIR__).'/helpers.php';require_admin();$pageTitle='Penggunaan Dana';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();if(($_POST['action']??'')==='delete'){$stmt=db()->prepare('DELETE FROM fund_usages WHERE id=?');$stmt->execute([(int)$_POST['id']]);flash('success','Catatan penggunaan dihapus.');}else{$amount=(float)preg_replace('/[^0-9]/','',$_POST['amount']??'0');$stmt=db()->prepare('INSERT INTO fund_usages(campaign_id,title,description,amount,usage_date) VALUES(?,?,?,?,?)');$stmt->execute([(int)$_POST['campaign_id'],trim($_POST['title']),trim($_POST['description']),$amount,$_POST['usage_date']]);flash('success','Penggunaan dana dicatat.');}redirect('admin/usages.php');}
$campaigns=db()->query("SELECT id,title FROM campaigns ORDER BY title")->fetchAll();$rows=db()->query("SELECT f.*,c.title campaign_title FROM fund_usages f JOIN campaigns c ON c.id=f.campaign_id ORDER BY f.usage_date DESC")->fetchAll();include dirname(__DIR__).'/partials/header.php';include __DIR__.'/nav.php';?>
<section class="admin-content container"><div class="admin-heading"><div><span class="eyebrow">Transparansi</span><h1>Penggunaan Dana</h1></div></div><div class="admin-split"><div class="glass form-card"><form method="post" class="stack-form"><?=csrf_field()?><label>Kampanye<select name="campaign_id" required><?php foreach($campaigns as $c):?><option value="<?=$c['id']?>"><?=e($c['title'])?></option><?php endforeach;?></select></label><label>Nama penggunaan<input name="title" required></label><label>Nominal<input name="amount" data-currency required></label><label>Tanggal penggunaan<input type="date" name="usage_date" value="<?=date('Y-m-d')?>" required></label><label>Deskripsi<textarea name="description" rows="5" required></textarea></label><button class="btn primary">Simpan Penggunaan</button></form></div><div class="glass panel"><h2>Riwayat penggunaan</h2><div class="usage-table"><?php foreach($rows as $r):?><div><div><strong><?=e($r['title'])?></strong><small><?=e($r['campaign_title'])?> · <?=date('d M Y',strtotime($r['usage_date']))?></small><p><?=e($r['description'])?></p></div><b><?=money((float)$r['amount'])?></b><form method="post" onsubmit="return confirm('Hapus catatan?')"><?=csrf_field()?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=$r['id']?>"><button class="text-danger">Hapus</button></form></div><?php endforeach;?></div></div></div></section>
<?php include dirname(__DIR__).'/partials/footer.php'; ?>
